INSERT INTO exam_questions (question, option_a, option_b, option_c, option_d, correct_index, hint) VALUES
('¿Qué describe mejor a una embarcación de recreo?', 'Cualquier tipo de embarcación que no sea una canoa.', 'Cualquier embarcación fabricada después de 1971.', 'Una embarcación fabricada y utilizada principalmente para fines no comerciales.', 'Una embarcación utilizada principalmente para fines comerciales.', 2, 'Piensa en la diferencia entre uso personal/familiar vs. uso para ganar dinero.'),
('¿Qué tipo de embarcación se mueve principalmente por la acción del viento sobre sus velas?', 'Bote de remo.', 'Velero.', 'Bote de motor.', 'PWC (Moto acuática).', 1, 'El nombre de este tipo de embarcación contiene la palabra ''vela''.'),
('¿Cuál es el nombre de la parte delantera de una embarcación?', 'Popa.', 'Babor.', 'Proa.', 'Estribor.', 2, 'Es una palabra de dos sílabas que empieza con ''P'' y está al frente.'),
('¿Cuál es el término para la parte posterior de una embarcación?', 'Proa.', 'Popa.', 'Babor.', 'Estribor.', 1, 'También empieza con ''P'' pero se refiere a la parte de atrás.'),
('¿Qué lado de la embarcación es "Babor"?', 'El lado derecho cuando se mira hacia la proa.', 'El lado izquierdo cuando se mira hacia la proa.', 'El lado derecho cuando se mira hacia la popa.', 'La parte de arriba de la embarcación.', 1, 'Babor es el lado izquierdo. Ambas palabras empiezan con consonantes.'),
('¿Qué lado de la embarcación es "Estribor"?', 'El lado derecho cuando se mira hacia la proa.', 'El lado izquierdo cuando se mira hacia la proa.', 'El lado derecho cuando se mira hacia la popa.', 'La parte de abajo de la embarcación.', 0, 'Estribor es el lado derecho. Ambas palabras empiezan con vocales.'),
('¿Cómo se llama la parte superior del costado de una embarcación?', 'Quilla.', 'Regala (Gunwale).', 'Espejo de popa (Transom).', 'Casco.', 1, 'Es el borde superior donde uno se puede apoyar o sentar.'),
('¿Qué tipo de casco permite que la embarcación se deslice sobre el agua a altas velocidades?', 'Casco de desplazamiento.', 'Casco de planeo.', 'Casco de fondo redondo.', 'Casco de quilla profunda.', 1, 'La palabra clave es ''planeo'' - como un avión que ''planea'' sobre la pista.'),
('¿Cuál es la función principal de la placa de capacidad de una embarcación?', 'Mostrar el nombre del fabricante.', 'Indicar el peso máximo y el número máximo de personas que la embarcación puede llevar con seguridad.', 'Indicar la velocidad máxima.', 'Mostrar la fecha de fabricación.', 1, 'Es sobre la CAPACIDAD - cuánto peso y cuántas personas puede transportar de forma segura.'),
('¿Dónde debe colocarse el número de registro en una embarcación?', 'En el espejo de popa.', 'En ambos lados de la mitad delantera (proa).', 'En la parte superior de la cabina.', 'En la quilla.', 1, 'Debe ser visible desde ambos lados y cerca del frente para identificación fácil.'),
('¿Qué es el "Calado" (Draft) de una embarcación?', 'La distancia desde la línea de flotación hasta la parte más alta.', 'La profundidad mínima de agua necesaria para que la embarcación flote.', 'El ancho máximo de la embarcación.', 'El peso total de la embarcación.', 1, 'Es importante saber qué tan profundo debe ser el agua para navegar sin tocar el fondo.'),
('¿Qué tipo de motor se monta generalmente en el exterior del espejo de popa?', 'Motor intraborda.', 'Motor fueraborda.', 'Motor de propulsión a chorro.', 'Motor diésel.', 1, 'Si está ''fuera'' del borde de la embarcación, es ''fuera-borda''.'),
('¿Qué equipo es obligatorio llevar en todas las embarcaciones de recreo para emergencias de hundimiento?', 'Una radio VHF.', 'Dispositivos de Flotación Personal (PFD) para cada persona a bordo.', 'Un GPS.', 'Una linterna estroboscópica.', 1, 'Lo más importante en caso de hundimiento es que las personas puedan flotar.'),
('¿Cuál es un requisito para los PFD (Chalecos Salvavidas)?', 'Deben ser de color azul oscuro.', 'Deben estar aprobados por la Guardia Costera de los EE. UU.', 'Deben tener al menos 10 años de antigüedad.', 'Deben guardarse en cajas cerradas con llave.', 1, 'La Guardia Costera es la autoridad que certifica equipos de seguridad marítima.'),
('¿Qué clase de extintor de incendios se requiere para incendios de líquidos inflamables (gasolina, aceite)?', 'Clase A.', 'Clase B.', 'Clase C.', 'Clase D.', 1, 'Clase B es para líquidos inflamables. Recuerda: B de Barril (líquidos).'),
('¿Qué dispositivo ayuda a ventilar los vapores de gasolina del compartimiento del motor?', 'Un ventilador eléctrico (Blower).', 'Una bomba de achique.', 'Un silbato.', 'Un ancla.', 0, 'Necesitas algo que ''sople'' o ventile el aire para sacar los vapores peligrosos.'),
('¿Qué luces de navegación deben mostrar las embarcaciones de motor durante la noche?', 'Luces rojas en ambos lados.', 'Una luz roja en babor, una verde en estribor y una blanca de todo horizonte.', 'Solo una luz blanca intermitente.', 'Luces azules y amarillas.', 1, 'Rojo = babor (izquierda), Verde = estribor (derecha), más una luz blanca.'),
('¿Cuál es la función de una señal acústica (pito o campana)?', 'Para atraer peces.', 'Para advertir a otras embarcaciones de su presencia o intenciones en condiciones de poca visibilidad.', 'Para anunciar la llegada al puerto.', 'Para comunicarse con el muelle.', 1, 'Es una herramienta de seguridad para ser escuchado cuando la visibilidad es limitada.'),
('¿Qué indica una boya con franjas verticales rojas y blancas?', 'Peligro inminente.', 'Aguas seguras (Mid-channel).', 'Zona de natación.', 'Obstrucción submarina.', 1, 'Las franjas rojas y blancas verticales indican que puedes navegar en medio del canal con seguridad.'),
('Según las Reglas de Navegación, ¿qué debe hacer una embarcación que es "cedente de paso"?', 'Mantener su curso y velocidad.', 'Tomar una acción temprana y sustancial para mantenerse alejada de la otra embarcación.', 'Aumentar la velocidad para pasar rápido.', 'Detener el motor de inmediato.', 1, 'Si debes ''ceder el paso'', debes moverte claramente para evitar la otra embarcación.'),
('¿Qué debe hacer una embarcación "privilegiada" (stand-on)?', 'Cambiar de dirección inmediatamente.', 'Mantener su curso y velocidad a menos que sea evidente que la otra embarcación no está cediendo el paso.', 'Tocar la bocina continuamente.', 'Dar la vuelta completa.', 1, 'Si tienes el privilegio de paso, mantente en tu curso para ser predecible.'),
('Cuando dos embarcaciones de motor se encuentran de frente, ¿qué deben hacer?', 'Ambas deben girar a babor (izquierda).', 'Ambas deben girar a estribor (derecha) para pasar por el lado de babor de la otra.', 'La más pequeña debe detenerse.', 'La más rápida tiene la preferencia.', 1, 'Como al conducir un auto, cada uno gira a su derecha para evitar colisión frontal.'),
('¿Quién tiene la preferencia de paso: un velero bajo vela o una embarcación de motor?', 'La embarcación de motor siempre.', 'El velero, a menos que esté adelantando a la embarcación de motor.', 'El que vaya por el lado derecho.', 'Depende del tamaño de las velas.', 1, 'Los veleros tienen limitaciones de maniobra, por eso generalmente tienen preferencia sobre motores.'),
('¿Cuál es el color de las boyas que marcan el lado derecho de un canal cuando se regresa del mar?', 'Verde.', 'Rojo.', 'Amarillo.', 'Negro.', 1, 'Recuerda: ''Rojo a la derecha al volver'' (Red Right Returning).'),
('¿Qué frase ayuda a recordar los colores de las boyas al entrar a puerto?', '''Verde a la derecha al volver''.', '''Rojo a la derecha al volver'' (Red Right Returning).', '''Blanco a la izquierda siempre''.', '''Azul al sur''.', 1, 'Es una regla mnemotécnica en inglés muy popular: Red Right Returning.'),
('¿Qué indica una boya blanca con un diamante naranja?', 'Zona de velocidad limitada.', 'Peligro (rocas, naufragio).', 'Información general.', 'Área prohibida.', 1, 'Un diamante naranja es una señal de advertencia de peligro.'),
('¿Qué indica una boya blanca con un círculo naranja?', 'Peligro.', 'Operaciones restringidas (ej. Límite de velocidad).', 'Área prohibida.', 'Amarre de botes.', 1, 'Un círculo indica control o restricción, como límites de velocidad.'),
('¿Cuál es el principal peligro de consumir alcohol mientras se navega?', 'Aumenta la velocidad de la embarcación.', 'Afecta el juicio, el equilibrio y el tiempo de reacción.', 'Mejora la visión nocturna.', 'Ayuda a mantener el calor corporal.', 1, 'El alcohol tiene los mismos efectos peligrosos en el agua que al conducir un auto.'),
('¿Qué sucede si un operador se niega a realizar una prueba de sobriedad?', 'No pasa nada.', 'Se le da una advertencia verbal.', 'Puede perder sus privilegios de navegación y enfrentar multas.', 'Debe pagar una pequeña propina.', 2, 'Negarse a la prueba tiene consecuencias legales graves, similar a las carreteras.'),
('¿A qué distancia mínima deben mantenerse las embarcaciones de una bandera de buceo ("Diver Down")?', '10 pies.', '50 pies.', '100 pies (en aguas abiertas generalmente más).', '500 pies.', 2, 'Los buceadores necesitan espacio considerable para seguridad.'),
('¿Qué debe hacer si alguien cae al agua (Hombre al agua)?', 'Seguir navegando y llamar a la policía.', 'Girar la popa (y la hélice) lejos de la persona y lanzarle un dispositivo de flotación.', 'Tirarse al agua de inmediato sin chaleco.', 'Aumentar la velocidad para buscar ayuda.', 1, 'Lo más importante es proteger a la persona de la hélice y darle algo para flotar.'),
('¿Cuál es el peligro del Monóxido de Carbono (CO)?', 'Es un gas visible y con olor a flores.', 'Es un gas incoloro, inodoro y altamente tóxico producido por los motores.', 'Ayuda a respirar mejor en el mar.', 'Solo se encuentra en los veleros.', 1, 'El CO es peligroso precisamente porque NO puedes verlo ni olerlo, pero es mortal.'),
('¿Qué debe hacer antes de llenar el tanque de gasolina en un muelle?', 'Dejar el motor encendido.', 'Apagar el motor y cerrar todas las escotillas y puertas.', 'Encender un cigarrillo para relajarse.', 'Mantener el radio a todo volumen.', 1, 'Los vapores de gasolina son extremadamente inflamables.'),
('¿Cuál es la causa principal de la mayoría de los accidentes fatales en embarcaciones?', 'Rayos.', 'Incendios.', 'Ahogamiento por no usar PFD tras caídas o vuelcos.', 'Ataques de tiburones.', 2, 'La mayoría de las muertes ocurren porque las personas no llevaban puesto su chaleco salvavidas.'),
('¿Qué factor meteorológico es más peligroso para un navegante?', 'El sol brillante.', 'Cambios repentinos en el viento y nubes oscuras (tormentas).', 'La marea baja.', 'La brisa suave.', 1, 'Las tormentas pueden aparecer rápidamente y crear condiciones peligrosas en minutos.'),
('¿Cómo se debe acercar una embarcación a un muelle para atracar?', 'A máxima velocidad.', 'Contra el viento o la corriente (lo que sea más fuerte) para un mejor control.', 'A favor del viento siempre.', 'De popa primero sin mirar.', 1, 'Ir contra el viento/corriente te permite frenar naturalmente y tener más control.'),
('¿Qué es el "Corte de seguridad del motor" (Engine Cut-Off Switch)?', 'Un interruptor para encender las luces.', 'Un dispositivo que apaga el motor si el operador cae por la borda.', 'Un botón para aumentar la potencia.', 'El control del aire acondicionado.', 1, 'Es un dispositivo de seguridad que se conecta al operador y detiene el motor si se separa.'),
('¿Qué documento debe llevarse a bordo siempre que la embarcación esté operando?', 'El certificado de título original.', 'El certificado de número de registro (original o copia según la ley).', 'El manual del motor.', 'Un mapa de carreteras.', 1, 'Similar a la licencia de conducir de un auto, necesitas el registro a bordo.'),
('¿Qué edad mínima se requiere en muchos estados para operar una PWC (Moto acuática) sin supervisión?', '8 años.', '10 años.', '14 o 16 años (varía por estado).', '21 años.', 2, 'Es similar a la edad para conducir ciclomotores - entre la adolescencia temprana y media.'),
('¿A qué hora está generalmente prohibido operar una PWC?', 'Al mediodía.', 'Entre la puesta del sol y la salida del sol (noche).', 'Durante la mañana.', 'Cuando hay otros botes cerca.', 1, 'Las PWC no tienen las luces de navegación requeridas para operación nocturna.'),
('¿Qué es necesario para que una PWC pueda girar?', 'Apagar el motor.', 'Tener potencia (aceleración). Si se suelta el acelerador, se pierde el control de dirección.', 'Bajar un ancla.', 'Moverse hacia la parte trasera.', 1, 'Las PWC necesitan el flujo de agua del motor para dirigir.'),
('¿Qué equipo adicional debe llevar una embarcación que remolca a un esquiador?', 'Un segundo motor.', 'Un observador competente o un espejo retrovisor de gran angular.', 'Una caña de pescar.', 'Luces de discoteca.', 1, 'El operador necesita observar al esquiador.'),
('¿Qué indica una bandera roja con una franja blanca diagonal?', 'Barco en peligro.', 'Buceador en el agua (Bandera de buceo recreativa).', 'Área de carreras.', 'Fin de la zona navegable.', 1, 'Esta bandera advierte que hay buceadores bajo el agua en el área.'),
('¿Cuál es la mejor manera de prevenir la propagación de especies acuáticas invasoras?', 'Pintar el bote de colores brillantes.', 'Lavar, drenar y secar el bote y el equipo antes de ir a otro cuerpo de agua.', 'Navegar solo en agua salada.', 'Dejar el agua acumulada en la sentina.', 1, 'Las especies invasoras viajan en el agua o adheridas al equipo - limpieza total es clave.'),
('¿Qué debe hacer si su embarcación se vuelca?', 'Tratar de nadar hacia la orilla aunque esté lejos.', 'Quedarse con la embarcación (flotar sobre ella o agarrarse).', 'Quitarse el chaleco salvavidas para nadar mejor.', 'Gritar hasta quedarse sin aliento.', 1, 'La embarcación es más visible para los rescatistas y te ayuda a conservar energía.'),
('¿Qué tipo de extintor debe llevar una embarcación de menos de 26 pies?', 'Al menos uno de Clase B-I.', 'Al menos tres de Clase A.', 'Ninguno.', 'Uno de Clase D.', 0, 'Embarcaciones pequeñas necesitan al menos un extintor Clase B tamaño I.'),
('¿Dónde se encuentra la línea de "Estribor"?', 'A la izquierda.', 'A la derecha.', 'Al frente.', 'Atrás.', 1, 'Recuerda: Estribor = Derecha.'),
('¿Qué información se encuentra en el Título de una embarcación?', 'El historial de pesca del dueño.', 'Prueba de propiedad de la embarcación.', 'El menú del puerto.', 'Las reglas de etiqueta.', 1, 'El título es el documento legal que prueba quién es el dueño.'),
('¿Qué es un "Plan de Flotación" (Float Plan)?', 'Un dibujo del bote.', 'Un documento dejado en tierra con detalles del viaje y personas a bordo.', 'El manual de instrucciones del ancla.', 'Una receta de comida marina.', 1, 'Es como dejar una nota diciendo a dónde vas y cuándo vuelves.'),
('¿Qué tipo de ancla es más común para embarcaciones pequeñas?', 'Ancla de cemento.', 'Ancla tipo Danforth o de arado.', 'Un bloque de madera.', 'Una cadena simple.', 1, 'Las anclas Danforth y de arado son diseños específicos muy efectivos para botes pequeños.'),
('¿Qué debe hacer si se encuentra en condiciones de niebla densa?', 'Aumentar la velocidad para salir rápido.', 'Reducir la velocidad a la mínima necesaria para mantener el rumbo y emitir señales sonoras.', 'Apagar todas las luces.', 'Anclar en medio del canal.', 1, 'En niebla, ve despacio, escucha y haz ruido para que otros te escuchen.'),
('¿Cuál es el propósito de las señales visuales de socorro (VDS)?', 'Para iluminar la cubierta en fiestas.', 'Para pedir ayuda en caso de emergencia.', 'Para asustar a las aves.', 'Para marcar el final de una carrera.', 1, 'VDS son herramientas para señalar que necesitas ayuda de emergencia.'),
('¿Qué es la "Hipotermia"?', 'Un exceso de energía.', 'Una pérdida peligrosa de calor corporal por exposición al agua o aire frío.', 'Una alergia al pescado.', 'Una técnica de buceo.', 1, '''Hipo'' significa bajo, ''termia'' se refiere a temperatura - baja temperatura corporal.'),
('¿Cuál es la regla de oro para el mantenimiento del motor?', 'Nunca cambiar el aceite.', 'Seguir el programa de mantenimiento del fabricante.', 'Usar gasolina con mucho etanol.', 'Solo revisarlo cuando se rompa.', 1, 'El fabricante sabe mejor que nadie cómo cuidar su motor.'),
('¿Qué indica una luz blanca visible desde todas las direcciones en una embarcación de motor de menos de 39.4 pies?', 'Que la embarcación está pescando.', 'Que la embarcación está anclada o navegando (según el contexto de otras luces).', 'Que es un barco de policía.', 'Que el barco está hundiéndose.', 1, 'Una luz blanca de 360° puede indicar diferentes cosas dependiendo de si hay otras luces encendidas.'),
('¿Cómo se llama la cuerda o cadena conectada al ancla?', 'Cabo de ancla (Rode).', 'Cordón.', 'Hilo.', 'Escota.', 0, 'En terminología náutica, la línea del ancla se llama ''rode'' o ''cabo de ancla''.'),
('¿A qué lado debe dejar una boya roja al navegar hacia aguas arriba?', 'Babor.', 'Estribor (Derecha).', 'Detrás.', 'Por debajo.', 1, 'Hacia arriba es como ''regresar'' al interior - aplica ''Rojo a la derecha al volver''.'),
('¿Qué significa "Navegación por estima" (Dead Reckoning)?', 'Adivinar dónde se está.', 'Calcular la posición actual basada en una posición anterior, velocidad y tiempo.', 'Usar solo el GPS.', 'Preguntar a otros navegantes.', 1, 'Es un cálculo matemático usando tu última posición conocida más tu velocidad y dirección.'),
('¿Qué es el "Escobén" (Hawsepipe)?', 'Una parte del motor.', 'El orificio por donde pasa la cadena del ancla.', 'Un tipo de remo.', 'Una ventana.', 1, 'Es el tubo o agujero en el casco por donde baja y sube la cadena del ancla.'),
('¿Cuál es el efecto de la corriente en la maniobrabilidad?', 'No tiene efecto.', 'Puede desviar la embarcación de su curso planeado.', 'Siempre ayuda a ir más rápido.', 'Solo afecta a los veleros.', 1, 'La corriente es como un río invisible que empuja tu embarcación hacia un lado.'),
('¿Qué es un "Nudo" en términos de velocidad náutica?', 'Una milla terrestre por hora.', 'Una milla náutica por hora.', 'Diez kilómetros por hora.', 'La longitud de una cuerda.', 1, 'En navegación, un nudo es la velocidad de una milla náutica por hora.'),
('¿Cuántos pies tiene una milla náutica aproximadamente?', '5,280 pies.', '6,076 pies.', '3,000 pies.', '10,000 pies.', 1, 'Una milla náutica es más larga que una milla terrestre - unos 6,076 pies.'),
('¿Qué es el "Francobordo" (Freeboard)?', 'La parte del barco bajo el agua.', 'La distancia desde la línea de flotación hasta la cubierta o regala.', 'El costo de estacionar el barco.', 'Un tipo de vela.', 1, 'Es la altura de la embarcación que está ''libre'' sobre el agua.'),
('¿Cuál es el uso de un "Bichero" (Boat hook)?', 'Para pescar tiburones.', 'Para ayudar a atracar o recuperar objetos del agua.', 'Para limpiar el motor.', 'Como remo de emergencia.', 1, 'Es una vara larga con gancho que te ayuda a alcanzar el muelle.'),
('¿Qué tipo de embarcación tiene prioridad en un canal estrecho?', 'La más pequeña y ágil.', 'Una embarcación grande que solo puede navegar con seguridad dentro del canal.', 'El que vaya más rápido.', 'Cualquiera que use remos.', 1, 'Los barcos grandes tienen menos capacidad de maniobra en canales estrechos.'),
('¿Qué debe hacer si ve una luz verde y una blanca en la noche?', 'Se acerca a un velero por babor.', 'Se acerca al lado de estribor de una embarcación de motor.', 'Se acerca a un barco anclado.', 'Debe detenerse inmediatamente.', 1, 'Verde = estribor (derecha). Estás viendo el lado derecho de otra embarcación.'),
('¿Qué significa "Estar al garete" (Adrift)?', 'Estar bien amarrado.', 'Estar sin control, moviéndose solo por el viento o corriente.', 'Estar navegando a vela.', 'Estar hundido.', 1, 'Estar ''a la deriva'' o ''al garete'' significa flotar sin control.'),
('¿Cuál es la función del "Arraigo" (Cleat)?', 'Medir la profundidad.', 'Asegurar las cuerdas (cabos) de amarre.', 'Decorar la proa.', 'Servir de asiento.', 1, 'Los cleats son las piezas de metal donde atas las cuerdas.'),
('¿Qué es el "Pantoque" (Bilge)?', 'La parte más alta del mástil.', 'La parte más baja del interior del casco donde se acumula el agua.', 'El timón.', 'La cabina del capitán.', 1, 'Es el ''sótano'' del barco donde el agua se acumula en el fondo.'),
('¿Para qué sirve una "Bomba de achique" (Bilge pump)?', 'Para inflar los chalecos.', 'Para sacar el agua que se acumula en el pantoque.', 'Para dar presión a la ducha.', 'Para enfriar el motor.', 1, 'La bomba de achique saca el agua acumulada del fondo del barco.'),
('¿Qué es un "Waypoints" en navegación GPS?', 'Un tipo de pez.', 'Coordenadas geográficas grabadas para marcar una posición o ruta.', 'El nombre de un fabricante de botes.', 'Una señal de tráfico marítimo.', 1, 'Son puntos de referencia que guardas en tu GPS para marcar lugares importantes.'),
('¿Qué es "Abatir" (Leeway)?', 'Ir muy rápido.', 'El movimiento lateral de una embarcación causado por el viento.', 'Anclar correctamente.', 'Limpiar el casco.', 1, 'El viento lateral empuja la embarcación hacia un lado.'),
('¿Cuál es el propósito de un "Ánodo de sacrificio"?', 'Como amuleto de buena suerte.', 'Para proteger las partes metálicas del motor de la corrosión galvánica.', 'Para pesar más el bote.', 'Para mejorar la estética.', 1, 'Se ''sacrifica'' corroyéndose él para proteger otras partes metálicas más importantes.'),
('¿Qué significa "Trim" en una embarcación de motor?', 'El color de la pintura.', 'El ángulo del motor respecto al espejo de popa para nivelar la embarcación.', 'Cortar el césped del muelle.', 'La limpieza de las velas.', 1, 'Ajustar el trim cambia el ángulo del motor para optimizar el desempeño.'),
('¿Qué es el "Paso" (Pitch) de una hélice?', 'El diámetro de la hélice.', 'La distancia teórica que avanza la hélice en una revolución completa.', 'El material de la hélice.', 'La velocidad de rotación.', 1, 'Como un tornillo, el ''paso'' es cuánto avanzaría la hélice en cada vuelta completa.'),
('¿Qué debe hacer si su motor se incendia?', 'Abrir la tapa del motor para ver mejor.', 'Cortar el suministro de combustible y usar el extintor.', 'Echarle gasolina para apagarlo.', 'Nadar lejos y dejar el bote solo.', 1, 'Primero elimina el combustible, luego apaga el fuego con el extintor apropiado.'),
('¿Qué es un "Aparato de gobierno" (Steering gear)?', 'El GPS.', 'El sistema que conecta el volante con el timón o motor.', 'La cocina del barco.', 'El equipo de pesca.', 1, 'Es el sistema mecánico que traduce el movimiento del volante en dirección del barco.'),
('¿Qué indica una boya con franjas horizontales rojas y verdes?', 'Una bifurcación en el canal; el color de arriba indica el canal preferido.', 'Zona de peligro absoluto.', 'Estacionamiento para botes.', 'Área de esquí acuático.', 0, 'Cuando el canal se divide, el color superior te dice cuál es el camino preferido.'),
('¿Qué es la "Manga" (Beam) de una embarcación?', 'El largo total.', 'El ancho máximo de la embarcación.', 'Un tipo de motor.', 'La profundidad del agua.', 1, 'La manga es la medida del ancho más amplio del barco.'),
('¿Qué es la "Estanqueidad"?', 'El color del agua.', 'La capacidad de un casco o estructura para evitar que entre agua.', 'Un tipo de pez.', 'La velocidad del viento.', 1, '''Estanco'' significa hermético, que no deja pasar agua.'),
('¿Qué es un "Defensa" (Fender)?', 'Un abogado marítimo.', 'Un cojín o parachoques para proteger el casco contra el muelle u otros botes.', 'El parachoques de un auto.', 'Una luz de navegación.', 1, 'Son los ''cojines'' que cuelgas del lado del barco para que no se raye al atracar.'),
('¿Qué es "Bornear" (Swinging)?', 'Bailar en cubierta.', 'El giro de una embarcación anclada alrededor de su ancla por viento o corriente.', 'Pescar con red.', 'Cambiar de capitán.', 1, 'Cuando estás anclado, el barco ''baila'' alrededor del ancla con el viento.'),
('¿Cuál es la función del "Espejo de popa" (Transom)?', 'Reflejar la luz del sol.', 'La parte plana de la popa donde se suelen montar los motores fueraborda.', 'Servir de ventana al mar.', 'Sujetar el mástil.', 1, 'Es la ''pared'' trasera plana del barco donde se atornilla el motor.'),
('¿Qué es la "Escora" (Heel)?', 'La parte trasera del pie.', 'La inclinación lateral de una embarcación, común en veleros.', 'Un tipo de ancla.', 'La velocidad máxima.', 1, 'Los veleros se ''inclinan'' hacia un lado con el viento - esa inclinación es la escora.'),
('¿Qué es un "Bichero" o "Boathook"?', 'Un dispositivo para atrapar peces.', 'Una vara con punta y gancho para ayudar en el atraque.', 'Un tipo de nudo.', 'Una parte del timón.', 1, 'Es una herramienta esencial para alcanzar el muelle o agarrar cuerdas desde lejos.');
